import React, {type FunctionComponent, isValidElement, useMemo} from 'react';
import {Heading, Text} from "../../../_compat";
import type {ILabelProps} from "@lmb-it/kitsconcerto-types";
import {useLanguage} from "../../../_compat";
import {useKitsTheme} from "../../../contexts/Theme";


const Label: FunctionComponent<ILabelProps> = ({as = 'label', className, label, elementId, required, style}) => {
    const {isRTL, t} = useLanguage();
    const {resolveToken} = useKitsTheme();

    const renderLabel = useMemo(() => {
        if(!label){
            return ''
        }
        if (isValidElement(label) || typeof label == "string") {
            return label;
        } else {
            if ('element' in label) {
                return label.element
            }
            if ('text' in label) {
                return label.text
            }
        }
        return '';
    }, [label])


    const labelState = useMemo(() => {

        const classes = ['w-full', 'label-position', 'kits-form-label'];

        if(className){
            classes.push(className)
        }
        if (typeof label === 'string') {
            if (isRTL) {
                classes.push('text-right');
            }
            classes.push('');
        } else {

            if (label && 'placement' in label) {
                if (label?.placement == 'RL') {
                    classes.push('RL');
                }
                if (label?.placement == 'B') {
                    classes.push('B');
                }
                if (label?.placement == 'T') {
                    classes.push('T');
                }
            }
        }
        return classes.join(' ');
    }, [isRTL]);

    const asterisk = required ? <span style={{color: resolveToken('danger'), marginInlineStart: 2}}>*</span> : null;

    if (!label) return null;

    // If the resolved label is already a ReactElement, render it directly without wrapping in Text/Heading
    if (isValidElement(renderLabel)) {
        return <>{renderLabel}{asterisk}</>;
    }

    if (["p", "span", "small", "label"].includes(as)) {
        // @ts-ignore
        return <Text as={as} className={labelState} htmlFor={elementId} style={style}>
                {renderLabel}{asterisk}
            </Text>;
    } else {
        // @ts-ignore
        return <Heading as={as} className={labelState} htmlFor={elementId} style={style}>
                {renderLabel}{asterisk}
            </Heading>;
    }

};

export default Label;
